import React, { useState } from "react";
import axios from "axios";
import Table from "react-bootstrap/Table";
import Button from "react-bootstrap/Button";
import Form from "react-bootstrap/Form";
import { useNavigate } from "react-router-dom"; // ✅ For auto-redirect

const FileUpload = () => {
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState([]);
  const [message, setMessage] = useState("");
  const [mappings, setMappings] = useState({});
  const navigate = useNavigate(); // ✅ Initialize navigation hook

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
  };

  const handleUpload = async () => {
    if (!file) {
      setMessage("Please select a file first!");
      return;
    }

    try {
      const formData = new FormData();
      formData.append("file", file);

      const token = localStorage.getItem("token");

      // ✅ Step 1: Upload the file
      const res = await axios.post(
        "http://localhost:4000/api/upload/upload",
        formData,
        {
          headers: {
            "Content-Type": "multipart/form-data",
            Authorization: `Bearer ${token}`,
          },
        }
      );

      setPreview(res.data.preview);
      setMessage("✅ File uploaded successfully, running reconciliation...");

      // ✅ Step 2: Automatically trigger reconciliation
      try {
        const reconcileRes = await axios.post(
          "http://localhost:4000/api/reconcile/run",
          {
            uploadedRecords: res.data.preview, // from uploaded file
            systemRecords: [
              // Mock/test system data — replace with your DB data later
              //{ transactionId: "TX001", amount: 100, referenceNumber: "REF123" },
              //{ transactionId: "TX002", amount: 100, referenceNumber: "REF124" },
              //{ transactionId: "TX003", amount: 150, referenceNumber: "REF125" },
            ],
          },
          {
            headers: {
              Authorization: `Bearer ${token}`,
            },
          }
        );

        console.log("✅ Reconciliation Summary:", reconcileRes.data.summary);
        setMessage("✅ File uploaded & reconciliation completed!");

        // ✅ Step 3: Redirect to dashboard automatically
        setTimeout(() => {
          navigate("/dashboard");
        }, 2000);
      } catch (err) {
        console.error("⚠️ Reconciliation failed:", err);
        setMessage("⚠️ Reconciliation failed after upload.");
      }
    } catch (err) {
      console.error("❌ Upload error:", err);
      setMessage("❌ File upload failed!");
    }
  };

  const handleMappingChange = (columnName, systemField) => {
    setMappings({ ...mappings, [columnName]: systemField });
  };

  const systemFields = [
    "Transaction ID",
    "Amount",
    "Reference Number",
    "Date",
  ];

  return (
    <div className="container mt-5">
      <h2>📤 File Upload & Column Mapping</h2>

      <div className="mb-3">
        <input type="file" onChange={handleFileChange} className="form-control" />
      </div>

      <Button onClick={handleUpload} variant="primary">
        Upload File
      </Button>

      {message && <p className="mt-3">{message}</p>}

      {preview.length > 0 && (
        <div className="mt-4">
          <h4>🧾 Preview (First 20 Rows)</h4>
          <Table striped bordered hover size="sm">
            <thead>
              <tr>
                {Object.keys(preview[0]).map((col) => (
                  <th key={col}>
                    {col}
                    <Form.Select
                      size="sm"
                      className="mt-1"
                      onChange={(e) =>
                        handleMappingChange(col, e.target.value)
                      }
                      value={mappings[col] || ""}
                    >
                      <option value="">-- Map to --</option>
                      {systemFields.map((field) => (
                        <option key={field} value={field}>
                          {field}
                        </option>
                      ))}
                    </Form.Select>
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {preview.map((row, idx) => (
                <tr key={idx}>
                  {Object.values(row).map((val, i) => (
                    <td key={i}>{val}</td>
                  ))}
                </tr>
              ))}
            </tbody>
          </Table>
        </div>
      )}

      {Object.keys(mappings).length > 0 && (
        <div className="mt-3">
          <h5>✅ Current Mappings</h5>
          <pre>{JSON.stringify(mappings, null, 2)}</pre>
        </div>
      )}
    </div>
  );
};

export default FileUpload;
